  OrderFilters,
  OrderListResult,
  EnrichedOrder,
  Order,
  CreateOrderInput,
  ServiceResult,
} from "../types.js";

/**
 * List orders with optional filtering. Always succeeds.
 * Handles: userId filtering, status filtering, revenue summary.
 */
export function listOrders(filters: OrderFilters): OrderListResult;

/**
 * Get a single order by ID with enriched items (product names joined in).
 * Fails with NOT_FOUND if order does not exist.
 */
export function getOrder(id: number): ServiceResult<EnrichedOrder>;

/**
 * Create a new order. Validates products exist, quantities > 0, stock sufficient.
 * Deducts stock and persists order.
 * Fails with VALIDATION_ERROR for any invalid input.
 */
export function createOrder(input: CreateOrderInput): ServiceResult<Order>;

/**
 * Update order status following the state machine.
 * Fails with NOT_FOUND if order does not exist.
 * Fails with VALIDATION_ERROR for invalid status or invalid transition.
 */
export function updateOrderStatus(id: number, status: string): ServiceResult<Order>;
```

### 4. Refactored Route Handler Structure

#### `src/routes/products.ts` (after refactoring)

```typescript
import { Router } from "express";
import { listProducts, getProduct, adjustStock } from "../services/product-service.js";

const router = Router();

router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;
  const result = listProducts({
    category: typeof category === "string" ? category : undefined,
    minPrice: typeof minPrice === "string" ? parseFloat(minPrice) || undefined : undefined,
    maxPrice: typeof maxPrice === "string" ? parseFloat(maxPrice) || undefined : undefined,
  });
  res.json(result);
});

router.get("/products/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const result = getProduct(id);
  if (!result.success) {
    res.status(404).json({ error: result.error });
    return;
  }
  res.json(result.data);
});

router.patch("/products/:id/stock", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const { adjustment } = req.body as { adjustment: unknown };
  const result = adjustStock(id, adjustment);
  if (!result.success) {
    const status = result.code === "NOT_FOUND" ? 404 : 400;
    res.status(status).json({ error: result.error });
    return;
  }
  res.json(result.data);
});

export { router as productRouter };
```

**Important nuance with `minPrice`/`maxPrice` parsing:** The current code at line 18-19 of products.ts does `parseFloat(minPrice)` and checks `!isNaN(min)` before applying the filter. A `parseFloat` that returns `NaN` effectively means the filter is skipped. The `|| undefined` in the route ensures that `NaN` becomes `undefined`, and the service only applies the filter when the value is defined. This preserves the current behavior exactly.

#### `src/routes/orders.ts` (after refactoring)

```typescript
import { Router } from "express";
import { listOrders, getOrder, createOrder, updateOrderStatus } from "../services/order-service.js";
import type { CreateOrderInput } from "../types.js";

const router = Router();

router.get("/orders", (req, res) => {
  const { userId, status } = req.query;
  const result = listOrders({
    userId: typeof userId === "string" ? parseInt(userId, 10) || undefined : undefined,
    status: typeof status === "string" ? status : undefined,
  });
  res.json(result);
});

router.get("/orders/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const result = getOrder(id);
  if (!result.success) {
    res.status(404).json({ error: result.error });
    return;
  }
  res.json(result.data);
});

router.post("/orders", (req, res) => {
  const input = req.body as CreateOrderInput;
  const result = createOrder(input);
  if (!result.success) {
    res.status(400).json({ error: result.error });
    return;
  }
  res.status(201).json(result.data);
});

router.patch("/orders/:id/status", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const { status } = req.body as { status: string };
  const result = updateOrderStatus(id, status);
  if (!result.success) {
    const httpStatus = result.code === "NOT_FOUND" ? 404 : 400;
    res.status(httpStatus).json({ error: result.error });
    return;
  }
  res.json(result.data);
});

export { router as orderRouter };
```

**Key observation about `createOrder`:** This route always maps failure to 400 (never 404), because all the failures from `createOrder` are validation errors (missing fields, bad product IDs, insufficient stock). The current code uses 400 for all of them. The route therefore only needs to check `result.success` and always returns 400 on failure.

